427	                            Some(LR::Right(x)) => vr.push(x),
428	                            _ => {}
429	                        }
430	                    }
431	
432	                    let mut vl2 = vl.clone();
433	                    let mut vr2 = vr.clone();
434	                    vl2.sort_unstable();
435	                    vr2.sort_unstable();
436	
437	                    assert_eq!(vl, vl2);
